import { useContext, useEffect, useRef, useState } from 'react'
import { DashboardV4VibrationEntity } from '../../entities/DashboardEntity'
import styles from './DashboardLevel4.module.css'
import { format, formatDate } from "date-fns"
import AppContext from "../../context"
import filterUtils from "../../utils/filter-utils"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import { FaAngleDoubleLeft, FaAngleDoubleRight, FaAngleLeft, FaAngleRight, FaArrowCircleLeft, FaChartLine, FaSortDown, FaSortUp, FaTable } from "react-icons/fa"
import { DashboardService } from "../../services/dashboard"
import { useLocation, useParams } from "react-router-dom"
import TableObserved from "../../components/Observer/observer"
import { GrLineChart } from "react-icons/gr"
import { TbTable } from "react-icons/tb"
import { BASE_URL } from '../../constants'


// ========================================= CHART IMPORT =========================================  //
import {
    Chart as ChartJS,
    LineElement,
    PointElement,
    LinearScale,
    Title,
    CategoryScale,
    Tooltip,
    Legend,
    ChartData,
    ChartOptions,
    defaults
} from 'chart.js'

import { Plugin } from 'chart.js'
import { Line } from 'react-chartjs-2'
import ExcelUtils from '../../utils/excel'

ChartJS.register(
    LineElement,
    PointElement,
    LinearScale,
    Title,
    CategoryScale,
    Tooltip,
    Legend
)

defaults.maintainAspectRatio = false
defaults.responsive = true
// ========================================= CHART IMPORT =========================================  //


interface VibrationPageProps {
    realtime: boolean
    setRealtime: (value: boolean) => void
    refresh: number
    start_date: Date
    end_date: Date
    setHandleGenerateExcel: (fn: (() => void) | null) => void
}


// ========================================= VIBRATION CONFIGURATION =========================================  //
interface VibrationAreaData {
    warn: number
    alarm: number
}
interface VibrationAreaDataRealtime {
    warn: number
    alarm: number
}

type VibrationChartType = "x" | "x_acc" | "z" | "z_acc" | "temp"

const VIBRATION_TYPES: VibrationChartType[] = ["x", "x_acc", "z", "z_acc", "temp"]

const LABEL_MAP: Record<VibrationChartType, string> = {
    x: "X Axis",
    x_acc: "X Acceleration",
    z: "Z Axis",
    z_acc: "Z Acceleration",
    temp: "Temperature"
}
// ========================================= VIBRATION CONFIGURATION =========================================  //


const VibrationPage: React.FC<VibrationPageProps> = ({ realtime, setRealtime, refresh, start_date, end_date, setHandleGenerateExcel }) => {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    // ========================================= GLOBAL CONTEXT =========================================  //


    const { machineId } = useParams()

    const CHART_COLORS = {
        chartLine: '#fb8500',
        graphicGood: 'rgba(41, 191, 18, 0.21)',
        graphicWarn: 'rgba(244, 188, 20, 0.28)',
        graphicAlarm: 'rgba(213, 14, 81, 0.2)',
    }

    const [activeHourIndex, setActiveHourIndex] = useState(new Date())
    const [isAuto, setIsAuto] = useState(true)
    const [viewMode, setViewMode] = useState<'chart' | 'table' | 'table-ool'>('chart')
    const [vibrationTypeChart, setVibrationTypeChart] = useState<VibrationChartType>("x")

    const [sortedCols, setSortedCols] = useState<keyof DashboardV4VibrationEntity | null>(null)
    const [sortedColsType, setSortedColsType] = useState<"ascending" | "descending">("ascending")

    // ========================================= STATE VIBRATION BY DATE =========================================  //
    const [tableData, setTableData] = useState<DashboardV4VibrationEntity[]>([])
    const [tableDataCache, setTableDataCache] = useState<DashboardV4VibrationEntity[]>([])

    const mappedDataRef = useRef<{ [key: string]: DashboardV4VibrationEntity[] }>({})

    const [tableDataFilter, setTableDataFilter] = useState<{ [key: string]: string }>({})

    const [chartData, setChartData] = useState<ChartData<'line'>>({ labels: [], datasets: [] })
    const [chartOptions, setChartOptions] = useState<ChartOptions<'line'>>({})

    const firstData = useRef<VibrationAreaData | null>(null)
    // ========================================= STATE VIBRATION BY DATE =========================================  //


    // ========================================= STATE VIBRATION REALTIME =========================================  //
    let vibrationSocket: WebSocket | null = null
    let reconnectVibration = true

    const [tableDataRealtime, setTableDataRealtime] = useState<DashboardV4VibrationEntity[]>([])
    const [tableDataRealtimeCache, setTableDataRealtimeCache] = useState<DashboardV4VibrationEntity[]>([])

    const [tableDataRealtimeFilter, setTableDataRealtimeFilter] = useState<{ [key: string]: string }>({})

    const [chartDataRealtime, setChartDataRealtime] = useState<ChartData<'line'>>({ labels: [], datasets: [] })
    const [chartOptionsRealtime, setChartOptionsRealtime] = useState<ChartOptions<'line'>>({})

    const firstDataRealtime = useRef<VibrationAreaDataRealtime | null>(null)
    // ========================================= STATE VIBRATION REALTIME =========================================  //


    const columns = [
        { key: "timestamp", label: "Waktu" },
        { key: "x", label: "X" },
        { key: "x_base", label: "X Base" },
        { key: "x_warn", label: "X Warn" },
        { key: "x_alarm", label: "X Alarm" },
        { key: "z", label: "Z" },
        { key: "z_base", label: "Z Base" },
        { key: "z_warn", label: "Z Warn" },
        { key: "z_alarm", label: "Z Alarm" },
        { key: "x_acc", label: "X Acc" },
        { key: "x_acc_base", label: "X Acc Base" },
        { key: "x_acc_warn", label: "X Acc Warn" },
        { key: "x_acc_alarm", label: "X Acc Alarm" },
        { key: "z_acc", label: "Z Acc" },
        { key: "z_acc_base", label: "Z Acc Base" },
        { key: "z_acc_warn", label: "Z Acc Warn" },
        { key: "z_acc_alarm", label: "Z Acc Alarm" },
        { key: "temp", label: "Temp" },
        { key: "temp_warn", label: "Temp Warn" },
        { key: "temp_alarm", label: "Temp Alarm" },
    ]
    function splitDataBy10Minutes(data: DashboardV4VibrationEntity[]) {
        const map: { [key: string]: DashboardV4VibrationEntity[] } = {}

        data.toReversed().forEach(item => {
            const date = new Date(item.timestamp)
            const rounded = new Date(date)
            rounded.setMinutes(Math.floor(date.getMinutes() / 10) * 10)
            rounded.setSeconds(0)
            rounded.setMilliseconds(0)

            const key = format(rounded, "yyyy-MM-dd HH:mm")

            if (map[key] == undefined) {
                map[key] = []
            } else {
                map[key].push(item)
            }
        })

        return map
    }
    function prepareChartData(mapData: { [key: string]: DashboardV4VibrationEntity[] }, vibrationType: VibrationChartType, activeHourIndex: Date) {
        const map: { [key: string]: DashboardV4VibrationEntity[] } = mapData

        // Find the group for the current activeHourIndex
        const flooredMinutes = `${Math.floor(activeHourIndex.getMinutes() / 10)}0`
        const key = format(activeHourIndex, "yyyy-MM-dd HH:" + `${flooredMinutes}`)

        const groupData = map[key] ?? []

        // Get Labels & Data
        const newLabels = groupData.map(msg => formatDate(msg.timestamp, "HH:mm:ss"))
        const newData = groupData.map(item => item[vibrationType])

        const groupDataReversed = groupData.toReversed()
        // Get Area Warn, Alarm & Good
        if (groupDataReversed[0]) {
            if (realtime) {
                firstDataRealtime.current = {
                    alarm: groupData[0][`${vibrationType}_alarm`] ?? 0,
                    warn: groupData[0][`${vibrationType}_warn`] ?? 0,
                }
            } else {
                firstData.current = {
                    alarm: groupData[0][`${vibrationType}_alarm`] ?? 0,
                    warn: groupData[0][`${vibrationType}_warn`] ?? 0,
                }
            }
        }

        // Calculate min & max y
        const dataMin = Math.min(...newData)
        const dataMax = Math.max(...newData)
        const range = dataMax - dataMin || 1
        const padding = 0.2

        const customMin = dataMin - range * padding
        const customMax = dataMax + range * padding

        return {
            chartData: {
                labels: newLabels,
                datasets: [
                    {
                        label: `${LABEL_MAP[vibrationType]}`,
                        data: newData,
                        borderColor: CHART_COLORS.chartLine,
                        pointBackgroundColor: CHART_COLORS.chartLine,
                        pointBorderColor: "#ffffff",
                        pointHoverBackgroundColor: "#ffffff",
                        pointHoverBorderColor: CHART_COLORS.chartLine,
                        borderWidth: 4,
                        pointRadius: 0,
                    },
                ],
            },
            customMin,
            customMax,
        }
    }


    // ========================================= FUNCTIONS VIBRATION BY DATE =========================================  //
    const statusArea: Plugin<'line'> = {
        id: 'statusArea',
        beforeDatasetsDraw(chart) {
            const vibrationData = firstData.current

            const { ctx, chartArea, scales } = chart
            if (!chartArea || !scales.x || !scales.y) {
                return
            }

            if (!vibrationData || (vibrationData.warn === 0 || vibrationData.warn == null) && (vibrationData.alarm === 0 || vibrationData.alarm == null)) {
                return
            }

            ctx.save()

            // --- Area Normal (Green) ---
            const startNormalArea = scales.y.min
            const endNormalArea = vibrationData ? vibrationData.warn : 0

            const startNormalAreaPixel = scales.y.getPixelForValue(startNormalArea)
            const endNormalAreaPixel = scales.y.getPixelForValue(endNormalArea)

            ctx.fillStyle = CHART_COLORS.graphicGood
            ctx.fillRect(
                chartArea.left,
                Math.min(startNormalAreaPixel, endNormalAreaPixel),
                chartArea.right - chartArea.left,
                Math.abs(startNormalAreaPixel - endNormalAreaPixel)
            )

            // --- Area Warn (Kuning) ---
            const startMinWarn = vibrationData ? vibrationData.warn : 0
            const endMinWarn = vibrationData ? vibrationData.alarm : 0

            const startMinWarnPixel = scales.y.getPixelForValue(startMinWarn)
            const endMinWarnPixel = scales.y.getPixelForValue(endMinWarn)

            ctx.fillStyle = CHART_COLORS.graphicWarn
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinWarnPixel, endMinWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinWarnPixel - endMinWarnPixel)
            )

            // --- Area Alarm (Merah) ---
            const startMinAlarm = vibrationData ? vibrationData.alarm : 0
            const endMinAlarm = scales.y.max

            const startMinAlarmPixel = scales.y.getPixelForValue(startMinAlarm)
            const endMinAlarmPixel = scales.y.getPixelForValue(endMinAlarm)

            ctx.fillStyle = CHART_COLORS.graphicAlarm
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinAlarmPixel, endMinAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinAlarmPixel - endMinAlarmPixel)
            )

            ctx.restore()
        }
    }
    const updateChart = (mapData: { [key: string]: DashboardV4VibrationEntity[] }, vibrationType: VibrationChartType, activeHourIndex: Date) => {
        const { chartData, customMin, customMax } = prepareChartData(mapData, vibrationType, activeHourIndex)
        setChartData(chartData)

        setChartOptions({
            responsive: true,
            maintainAspectRatio: false,
            animation: {
                duration: 800,
                easing: 'easeInOutCubic',
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        color: '#fbeecc',
                        font: {
                            size: 14,
                            weight: 500,
                            family: "'Inter', 'Segoe UI', sans-serif",
                        },
                        usePointStyle: true,
                        pointStyle: 'rectRounded',
                    },
                },
                tooltip: {
                    backgroundColor: '#1f2937',
                    titleColor: '#f8fafc',
                    bodyColor: '#cbd5e1',
                    padding: 12,
                    borderColor: '#0077b6',
                    borderWidth: 1,
                    cornerRadius: 8,
                    titleFont: {
                        family: "'Inter', sans-serif",
                        size: 14,
                        weight: 600,
                    },
                    bodyFont: {
                        family: "'Inter', sans-serif",
                        size: 13,
                    },
                },
            },
            scales: {
                x: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        maxRotation: 45,
                        minRotation: 0,
                    },
                },
                y: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        padding: 8,
                    },
                    min: customMin,
                    max: customMax,
                },
            },
            layout: {
                padding: {
                    top: 10,
                    bottom: 10,
                    left: 10,
                    right: 10,
                },
            },
            elements: {
                line: {
                    borderJoinStyle: 'round',
                },
                point: {
                    pointStyle: 'circle',
                },
            },
        })
    }

    const handleFilterAndSort = () => {
        const table_filtered = tableDataCache.filter((row) => {
            return filterUtils.FilterTable(row, tableDataFilter)
        }).sort((a, b) => {
            if (!sortedCols) { return 0 }
            if (sortedColsType == "ascending") {
                return filterUtils.SortingTable(a, b, sortedCols)
            } else {
                return filterUtils.SortingTable(b, a, sortedCols)
            }
        })
        setTableData(table_filtered)
    }
    const filterTable = (column: keyof DashboardV4VibrationEntity, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", width: "150px" }} type="text" value={tableDataFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }
    const headerTable = (column: keyof DashboardV4VibrationEntity, columnName?: string) => {
        return <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
            onClick={() => {
                setSortedCols(column)
                if (sortedColsType === "ascending") {
                    setSortedColsType("descending")
                } else {
                    setSortedColsType("ascending")
                }
            }}
        >
            <div>{columnName ?? column}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}>
                <FaSortUp style={{ color: ((sortedCols == column && sortedColsType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                <FaSortDown style={{ color: ((sortedCols == column && sortedColsType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
            </div>
        </div>
    }

    const generateData = async (withLoading: boolean) => {
        if (withLoading) {
            contextShowLoadingFunc(true)
        }

        try {
            const resp = await DashboardService.GetDashboardLevel4Vibration(
                Number(machineId),
                formatDate(start_date, 'yyyy-MM-dd'),
                formatDate(end_date, 'yyyy-MM-dd')
            )
            setTableData(resp)
            setTableDataCache(resp)

            const map = splitDataBy10Minutes(resp)
            mappedDataRef.current = map

            const keys = Object.keys(map)
            if (keys.length > 0) {
                const newDate = new Date(keys[keys.length - 1])
                setActiveHourIndex(newDate)
                updateChart(mappedDataRef.current, vibrationTypeChart, newDate)
            } else {
                updateChart(mappedDataRef.current, vibrationTypeChart, activeHourIndex)
            }

        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({
                message: error instanceof Error ? error.message : error.toString(),
                level: 3
            }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }
    const vibrationDataRows = (index: number, row: DashboardV4VibrationEntity) => {
        const styleX = getCollorRows(row.x, row.x_warn, row.x_alarm)
        const styleXAcc = getCollorRows(row.x_acc, row.x_acc_warn, row.x_acc_alarm)
        const styleZ = getCollorRows(row.z, row.z_warn, row.z_alarm)
        const styleZAcc = getCollorRows(row.z_acc, row.z_acc_warn, row.z_acc_alarm)
        const styleTemp = getCollorRows(row.temp, row.temp_warn, row.temp_alarm)

        return <>
            <td>{index + 1}</td>
            <td>{format(row.timestamp, `yyyy-MM-dd HH:mm:ss`)}</td>
            <td style={{ color: styleX.color, fontWeight: styleX.weight }}>{row.x}</td>
            <td>{row.x_base}</td>
            <td>{row.x_warn}</td>
            <td>{row.x_alarm}</td>
            <td style={{ color: styleZ.color, fontWeight: styleZ.weight }}>{row.z}</td>
            <td>{row.z_base}</td>
            <td>{row.z_warn}</td>
            <td>{row.z_alarm}</td>
            <td style={{ color: styleXAcc.color, fontWeight: styleXAcc.weight }}>{row.x_acc}</td>
            <td>{row.x_acc_base}</td>
            <td>{row.x_acc_warn}</td>
            <td>{row.x_acc_alarm}</td>
            <td style={{ color: styleZAcc.color, fontWeight: styleZAcc.weight }}>{row.z_acc}</td>
            <td>{row.z_acc_base}</td>
            <td>{row.z_acc_warn}</td>
            <td>{row.z_acc_alarm}</td>
            <td style={{ color: styleTemp.color, fontWeight: styleTemp.weight }}>{row.temp}</td>
            <td>{row.temp_warn}</td>
            <td>{row.temp_alarm}</td>
        </>
    }

    const getCollorRows = (value: number, warn: number | undefined, alarm: number | undefined) => {
        let valueColor = 'black'
        let valueWeight = '400'

        if (warn != undefined && value < warn) {
            valueColor = 'green'
            valueWeight = 'bold'
        }

        if (warn != undefined && value >= warn) {
            valueColor = 'orange'
            valueWeight = 'bold'
        }

        if (alarm != undefined && value >= alarm) {
            valueColor = 'red'
            valueWeight = 'bold'
        }

        return {
            color: valueColor,
            weight: valueWeight
        }
    }

    useEffect(() => {
        handleFilterAndSort()
    }, [tableDataFilter, sortedCols, sortedColsType])
    useEffect(() => {
        // no loading on first open
        generateData(refresh != 0)
    }, [refresh])
    // ========================================= FUNCTIONS VIBRATION BY DATE =========================================  //


    // ========================================= FUNCTIONS VIBRATION REALTIME =========================================  //
    const statusAreaRealtime: Plugin<'line'> = {
        id: 'statusAreaRealtime',
        beforeDatasetsDraw(chart) {
            const vibrationData = firstDataRealtime.current

            const { ctx, chartArea, scales } = chart
            if (!chartArea || !scales.x || !scales.y) {
                return
            }

            if (!vibrationData || (vibrationData.warn === 0 || vibrationData.warn == null) && (vibrationData.alarm === 0 || vibrationData.alarm == null)) {
                return
            }

            ctx.save()

            // --- Area Normal (Green) ---
            const startNormalArea = scales.y.min
            const endNormalArea = vibrationData ? vibrationData.warn : 0

            const startNormalAreaPixel = scales.y.getPixelForValue(startNormalArea)
            const endNormalAreaPixel = scales.y.getPixelForValue(endNormalArea)

            ctx.fillStyle = CHART_COLORS.graphicGood
            ctx.fillRect(
                chartArea.left,
                Math.min(startNormalAreaPixel, endNormalAreaPixel),
                chartArea.right - chartArea.left,
                Math.abs(startNormalAreaPixel - endNormalAreaPixel)
            )

            // --- Area Warn (Kuning) ---
            const startMinWarn = vibrationData ? vibrationData.warn : 0
            const endMinWarn = vibrationData ? vibrationData.alarm : 0

            const startMinWarnPixel = scales.y.getPixelForValue(startMinWarn)
            const endMinWarnPixel = scales.y.getPixelForValue(endMinWarn)

            ctx.fillStyle = CHART_COLORS.graphicWarn
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinWarnPixel, endMinWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinWarnPixel - endMinWarnPixel)
            )

            // --- Area Alarm (Merah) ---
            const startMinAlarm = vibrationData ? vibrationData.alarm : 0
            const endMinAlarm = scales.y.max

            const startMinAlarmPixel = scales.y.getPixelForValue(startMinAlarm)
            const endMinAlarmPixel = scales.y.getPixelForValue(endMinAlarm)

            ctx.fillStyle = CHART_COLORS.graphicAlarm
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinAlarmPixel, endMinAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinAlarmPixel - endMinAlarmPixel)
            )

            ctx.restore()
        }
    }
    const updateChartRealtime = (mapData: { [key: string]: DashboardV4VibrationEntity[] }, vibrationType: VibrationChartType, activeHourIndex: Date) => {
        const { chartData, customMin, customMax } = prepareChartData(
            mapData,
            vibrationType,
            activeHourIndex
        )
        setChartDataRealtime(chartData)

        setChartOptionsRealtime({
            responsive: true,
            maintainAspectRatio: false,
            animation: {
                duration: 800,
                easing: 'easeInOutCubic',
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        color: '#fbeecc',
                        font: {
                            size: 14,
                            weight: 500,
                            family: "'Inter', 'Segoe UI', sans-serif",
                        },
                        usePointStyle: true,
                        pointStyle: 'rectRounded',
                    },
                },
                tooltip: {
                    backgroundColor: '#1f2937',
                    titleColor: '#f8fafc',
                    bodyColor: '#cbd5e1',
                    padding: 12,
                    borderColor: '#0077b6',
                    borderWidth: 1,
                    cornerRadius: 8,
                    titleFont: {
                        family: "'Inter', sans-serif",
                        size: 14,
                        weight: 600,
                    },
                    bodyFont: {
                        family: "'Inter', sans-serif",
                        size: 13,
                    },
                },
            },
            scales: {
                x: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        maxRotation: 45,
                        minRotation: 0,
                    },
                },
                y: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        padding: 8,
                    },
                    min: customMin,
                    max: customMax,
                },
            },
            layout: {
                padding: {
                    top: 10,
                    bottom: 10,
                    left: 10,
                    right: 10,
                },
            },
            elements: {
                line: {
                    borderJoinStyle: 'round',
                },
                point: {
                    pointStyle: 'circle',
                },
            }
        })
    }

    const handleFilterAndSortRealtime = () => {
        const table_filtered = tableDataRealtimeCache.filter((row) => {
            return filterUtils.FilterTable(row, tableDataRealtimeFilter)
        }).sort((a, b) => {
            if (!sortedCols) { return 0 }
            if (sortedColsType == "ascending") {
                return filterUtils.SortingTable(a, b, sortedCols)
            } else {
                return filterUtils.SortingTable(b, a, sortedCols)
            }
        })
        setTableDataRealtime(table_filtered)
    }
    const filterTableRealtime = (column: keyof DashboardV4VibrationEntity, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", width: "150px" }} type="text" value={tableDataRealtimeFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataRealtimeFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }
    const headerTableRealtime = (column: keyof DashboardV4VibrationEntity, columnName?: string) => {
        return <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
            onClick={() => {
                setSortedCols(column)
                if (sortedColsType === "ascending") {
                    setSortedColsType("descending")
                } else {
                    setSortedColsType("ascending")
                }
            }}
        >
            <div>{columnName ?? column}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}>
                <FaSortUp style={{ color: ((sortedCols == column && sortedColsType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                <FaSortDown style={{ color: ((sortedCols == column && sortedColsType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
            </div>
        </div>
    }

    const connectVibration = () => {
        if (!reconnectVibration) {
            console.log("canceled")
            return
        }

        return new Promise((resolve, reject) => {
            try {
                vibrationSocket = new WebSocket(`${BASE_URL}/ws/realtime/vibration`)

                vibrationSocket.onmessage = (event: MessageEvent) => {
                    try {
                        const response = JSON.parse(event.data)
                        setTableDataRealtime(response.data)
                        setTableDataRealtimeCache(response.data)
                    } catch (error: any) {
                        console.log("Invalid response: ", error.message)
                    }
                }

                vibrationSocket.onerror = (err) => {
                    console.error("WebSocket error:", err)
                    vibrationSocket?.close()
                }

                vibrationSocket.onclose = async () => {
                    console.log("vibrationSocket closed.")
                    console.log("Try reconnecting...")
                    try {
                        await connectVibration()
                    } catch (error) {
                        console.log("Failed to reconnect")
                    }
                }

                vibrationSocket.onopen = () => {
                    console.log("vibrationSocket connected")
                    const machineIdPayload = {
                        type: "subscribe",
                        machine_id: machineId,
                    }
                    vibrationSocket?.send(JSON.stringify(machineIdPayload))
                    resolve(true)
                }
            } catch (error) {
                console.log("Error reconnect: ", error)
                reject(false)
            }
        })
    }

    useEffect(() => {
        if (vibrationSocket == null || vibrationSocket.readyState == WebSocket.CLOSED) {
            console.log("Connecting ws vibration...")
            connectVibration()
        }
        return () => {
            if (vibrationSocket != null) {
                console.log("Disconnecting ws vibration...")
                vibrationSocket.close()
            }
            reconnectVibration = false
        }
    }, [vibrationSocket])
    useEffect(() => {
        handleFilterAndSortRealtime()
    }, [tableDataRealtimeFilter, sortedCols, sortedColsType])
    // ========================================= FUNCTIONS VIBRATION REALTIME =========================================  //


    // Auto mode
    useEffect(() => {
        if (!realtime) { return }
        if (!isAuto) { return }

        const map = splitDataBy10Minutes(tableDataRealtime)
        const newDate = new Date()
        newDate.setMinutes(Math.floor(newDate.getMinutes() / 10) * 10)

        setActiveHourIndex(newDate)
        updateChartRealtime(map, vibrationTypeChart, newDate)
    }, [isAuto, realtime, tableDataRealtime, vibrationTypeChart])

    // Manual mode
    useEffect(() => {
        if (!realtime) { return }
        if (isAuto) { return }

        const map = splitDataBy10Minutes(tableDataRealtime)
        updateChartRealtime(map, vibrationTypeChart, activeHourIndex)
    }, [isAuto, realtime, tableDataRealtime, vibrationTypeChart, activeHourIndex])

    const handleChangeActiveHourIndex = (amount: number, unit: 'hours' | 'minutes') => {
        setIsAuto(false)
        const newDate = new Date(activeHourIndex)
        const flooredMinutes = Math.floor(newDate.getMinutes() / 10) * 10
        if (unit === 'hours') {
            newDate.setHours(newDate.getHours() + amount, flooredMinutes, 0, 0)
        } else if (unit === 'minutes') {
            newDate.setHours(newDate.getHours(), flooredMinutes + amount, 0, 0)
        }

        setActiveHourIndex(newDate)
        if (!realtime) {
            updateChart(mappedDataRef.current, vibrationTypeChart, newDate)
        }
    }

    const handleSetPage = (page: "chart" | "table" | "table-ool", realtime: boolean) => {
        // set state
        setViewMode(page);
        setRealtime(realtime);

        // reset everything
        setSortedCols(null);
        setSortedColsType("ascending")

        // update chart
        if (page == "chart") {
            if (realtime) {
                const map = splitDataBy10Minutes(tableDataRealtime)
                updateChartRealtime(map, vibrationTypeChart, activeHourIndex)
            } else {
                updateChart(mappedDataRef.current, vibrationTypeChart, activeHourIndex)
            }
        }
    }

    const handleToggle = () => {
        setIsAuto((prev) => !prev)
    }

    // excel
    const generateExcelRealtime = () => {
        if (tableDataRealtime.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = [
            "timestamp", "x", "x_base", "x_warn", "x_alarm",
            "z", "z_base", "z_warn", "z_alarm",
            "x_acc", "x_acc_base", "x_acc_warn", "x_acc_alarm",
            "z_acc", "z_acc_base", "z_acc_warn", "z_acc_alarm",
            "temp", "temp_warn", "temp_alarm",
        ]

        let values: { [key: string]: string }[] = []

        for (let i = 0; i < tableData.length; i++) {
            const item = tableData[i] as DashboardV4VibrationEntity

            values.push({
                timestamp: format(
                    typeof item.timestamp === "string" ? new Date(item.timestamp) : item.timestamp,
                    "yyyy-MM-dd HH:mm:ss"
                ),

                x: `${item.x}`,
                x_base: `${item.x_base}`,
                x_warn: `${item.x_warn ?? ""}`,
                x_alarm: `${item.x_alarm ?? ""}`,

                z: `${item.z}`,
                z_base: `${item.z_base}`,
                z_warn: `${item.z_warn ?? ""}`,
                z_alarm: `${item.z_alarm ?? ""}`,

                x_acc: `${item.x_acc}`,
                x_acc_base: `${item.x_acc_base}`,
                x_acc_warn: `${item.x_acc_warn ?? ""}`,
                x_acc_alarm: `${item.x_acc_alarm ?? ""}`,

                z_acc: `${item.z_acc}`,
                z_acc_base: `${item.z_acc_base}`,
                z_acc_warn: `${item.z_acc_warn ?? ""}`,
                z_acc_alarm: `${item.z_acc_alarm ?? ""}`,

                temp: `${item.temp}`,
                temp_warn: `${item.temp_warn ?? ""}`,
                temp_alarm: `${item.temp_alarm ?? ""}`
            })
        }

        ExcelUtils.export(`Vibration Data Realtime`, column, values)
    }
    const generateExcel = () => {
        if (tableData.length === 0) {
            return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 }))
        }

        const column = [
            "timestamp", "x", "x_base", "x_warn", "x_alarm",
            "z", "z_base", "z_warn", "z_alarm",
            "x_acc", "x_acc_base", "x_acc_warn", "x_acc_alarm",
            "z_acc", "z_acc_base", "z_acc_warn", "z_acc_alarm",
            "temp", "temp_warn", "temp_alarm",
        ]

        let values: { [key: string]: string }[] = []

        for (let i = 0; i < tableData.length; i++) {
            const item = tableData[i] as DashboardV4VibrationEntity

            values.push({
                timestamp: format(
                    typeof item.timestamp === "string" ? new Date(item.timestamp) : item.timestamp,
                    "yyyy-MM-dd HH:mm:ss"
                ),

                x: `${item.x}`,
                x_base: `${item.x_base}`,
                x_warn: `${item.x_warn ?? ""}`,
                x_alarm: `${item.x_alarm ?? ""}`,

                z: `${item.z}`,
                z_base: `${item.z_base}`,
                z_warn: `${item.z_warn ?? ""}`,
                z_alarm: `${item.z_alarm ?? ""}`,

                x_acc: `${item.x_acc}`,
                x_acc_base: `${item.x_acc_base}`,
                x_acc_warn: `${item.x_acc_warn ?? ""}`,
                x_acc_alarm: `${item.x_acc_alarm ?? ""}`,

                z_acc: `${item.z_acc}`,
                z_acc_base: `${item.z_acc_base}`,
                z_acc_warn: `${item.z_acc_warn ?? ""}`,
                z_acc_alarm: `${item.z_acc_alarm ?? ""}`,

                temp: `${item.temp}`,
                temp_warn: `${item.temp_warn ?? ""}`,
                temp_alarm: `${item.temp_alarm ?? ""}`
            })
        }

        ExcelUtils.export("Vibration Data", column, values)
    }

    useEffect(() => {
        if (realtime) {
            setHandleGenerateExcel(() => generateExcelRealtime)
        } else {
            setHandleGenerateExcel(() => generateExcel)
        }

        return () => {
            setHandleGenerateExcel(null)
        }
    }, [realtime, tableDataRealtime, tableData])

    return <>
        <div className={styles.cardBodyHeader}>

            {/* Realtime */}
            {viewMode === 'chart' && realtime && (
                <>
                    <div className={styles.headerChart}>
                        <div className={styles.chartButtons}>
                            {VIBRATION_TYPES.map((type) => (
                                <button
                                    key={type}
                                    onClick={() => setVibrationTypeChart(type)}
                                    className={vibrationTypeChart === type ? styles.activeBtn : ""}
                                >
                                    {LABEL_MAP[type]}
                                </button>
                            ))}
                        </div>
                        <div className={styles.titleChart}>{formatDate(activeHourIndex, "dd MMM yyyy HH:mm")}</div>
                        <div></div>
                    </div>
                    <div className={styles.bodyChart}>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0 0 0 12px' }} onClick={() => {
                            handleChangeActiveHourIndex(-1, "hours")
                        }}><FaAngleDoubleLeft /></button>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(-10, "minutes")
                        }}><FaAngleLeft /></button>
                        <div className={styles.wrapperChart}>
                            <Line data={chartDataRealtime} options={chartOptionsRealtime} plugins={[statusAreaRealtime]} />
                        </div>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(10, "minutes")
                        }}><FaAngleRight /></button>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0 12px 12px 0' }} onClick={() => {
                            handleChangeActiveHourIndex(1, "hours")
                        }}><FaAngleDoubleRight /></button>
                    </div>
                </>
            )}
            {viewMode === 'table' && realtime && (
                <>
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th>No</th>
                                    {columns.map((col) => (
                                        <th
                                            key={col.key}
                                            className={col.key === "timestamp" ? "wide-timestamp" : ""}
                                        >
                                            {headerTableRealtime(col.key as keyof DashboardV4VibrationEntity, col.label)}
                                            {filterTableRealtime(col.key as keyof DashboardV4VibrationEntity, col.label)}
                                        </th>
                                    ))}
                                </tr>
                            </thead>
                            {!filterUtils.FastIsEmpty(tableDataRealtime)
                                ? <tbody>
                                    <TableObserved
                                        tableData={tableDataRealtime}
                                        rowFunction={vibrationDataRows}
                                        rowsCount={250}
                                        rowsIncrement={50}
                                    />
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>
                </>
            )}

            {/* By Date */}
            {viewMode === 'chart' && !realtime && (
                <>
                    <div className={styles.headerChart}>
                        <div className={styles.chartButtons}>
                            {VIBRATION_TYPES.map((type) => (
                                <button
                                    key={type}
                                    onClick={() => { setVibrationTypeChart(type); updateChart(mappedDataRef.current, type, activeHourIndex) }}
                                    className={vibrationTypeChart === type ? styles.activeBtn : ""}
                                >
                                    {LABEL_MAP[type]}
                                </button>
                            ))}
                        </div>
                        <div className={styles.titleChart}>{formatDate(activeHourIndex, "dd MMM yyyy HH:mm")}</div>
                        <div></div>
                    </div>
                    <div className={styles.bodyChart}>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0 0 0 12px' }} onClick={() => {
                            handleChangeActiveHourIndex(-1, "hours")
                        }}><FaAngleDoubleLeft /></button>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(-10, "minutes")
                        }}><FaAngleLeft /></button>
                        <div className={styles.wrapperChart}>
                            <Line data={chartData} options={chartOptions} plugins={[statusArea]} />
                        </div>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(10, "minutes")
                        }}><FaAngleRight /></button>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0 12px 12px 0' }} onClick={() => {
                            handleChangeActiveHourIndex(1, "hours")
                        }}><FaAngleDoubleRight /></button>
                    </div>
                </>
            )}
            {viewMode === 'table' && !realtime && (
                <>
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th>No</th>
                                    {columns.map((col) => (
                                        <th
                                            key={col.key}
                                            className={col.key === "timestamp" ? "wide-timestamp" : ""}
                                        >
                                            {headerTable(col.key as keyof DashboardV4VibrationEntity, col.label)}
                                            {filterTable(col.key as keyof DashboardV4VibrationEntity, col.label)}
                                        </th>
                                    ))}
                                </tr>
                            </thead>
                            {!filterUtils.FastIsEmpty(tableData)
                                ? <tbody>
                                    <TableObserved
                                        tableData={tableData}
                                        rowFunction={vibrationDataRows}
                                        rowsCount={250}
                                        rowsIncrement={50}
                                    />
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>
                </>
            )}

        </div>

        <div className={styles.cardBodyFooter}>
            <div className={styles.footerLeft}>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'chart' && realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage("chart", true) }}>
                    <GrLineChart />
                    <span className={styles.tooltipText}>Realtime Chart</span>
                </button>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'table' && realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage("table", true) }}>
                    <TbTable />
                    <span className={styles.tooltipText}>Realtime Table</span>
                </button>
            </div>
            <div className={styles.footerMid}>
                {viewMode === 'chart' && realtime && (
                    <div className={styles.switchGroup}>
                        <label htmlFor="auto">Auto</label>
                        <label className={styles.switch}>
                            <input type="checkbox" id="auto" checked={isAuto} onChange={handleToggle} />
                            <span className={styles.slider}></span>
                        </label>
                    </div>
                )}
            </div>
            <div className={styles.footerRight}>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'chart' && !realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage("chart", false) }}>
                    <FaChartLine />
                    <span className={styles.tooltipText}>Chart</span>
                </button>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'table' && !realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage("table", false) }}>
                    <FaTable />
                    <span className={styles.tooltipText}>Table</span>
                </button>
            </div>
        </div>
    </>
}

export default VibrationPage
